import React, { useState } from "react";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
//import '../assets/AdminPanel.css'

function AdminLogin() {
  const [phoneNumber, setPhoneNumber] = useState("");
  const [otp, setOtp] = useState("");
  const [generatedOtp, setGeneratedOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  function handleSendOtp(e) {
    e.preventDefault();

    if (!/^\d{10}$/.test(phoneNumber)) {
      setError("Phone number must be 10 digits");
      return;
    }

    setLoading(true);

    setTimeout(function () {
      const fakeOtp = Math.floor(100000 + Math.random() * 900000).toString();
      setGeneratedOtp(fakeOtp);
      console.log("Generated OTP:", fakeOtp);

      setOtpSent(true);
      setSuccess("OTP sent successfully! (Check console)");
      setError("");
      setLoading(false);

      setTimeout(function () {
        setSuccess("");
      }, 1500);
    }, 500);
  }

  function handleVerifyOtp(e) {
    e.preventDefault();

    if (!/^\d{6}$/.test(otp)) {
      setError("OTP must be 6 digits");
      return;
    }

    setLoading(true);

    setTimeout(function () {
      if (otp === generatedOtp) {
        Cookies.set("adminToken", "fake-admin-token", { expires: 7 });
        Cookies.set("adminPhoneNumber", phoneNumber, { expires: 7 });

        setSuccess("Logged in Successfully!");
        setError("");

        setTimeout(function () {
          navigate("/users");
        }, 800);
      } else {
        setError("Invalid OTP");
      }

      setLoading(false);
    }, 500);
  }

  return (
    <div className="container d-flex flex-column align-items-center justify-content-center min-vh-100">
      <img
        loading="lazy"
        className="img-fluid mb-4"
        style={{ width: "220px", height: "auto" }}
        src="https://equitypandit.in/ep-imgs/ep-advisor-logo.svg"
        alt="EP-Investment-Advisor"
      />

      <div
        className="card shadow-md border-0 rounded p-4"
        style={{ maxWidth: "500px", width: "100%" }}
      >
        <div className="card-body">
          <h2 className="text-center fw-bold text-dark mb-4">Admin Login</h2>

          {success && <div className="alert alert-success">{success}</div>}

          {error && <div className="alert alert-danger">{error}</div>}

          {!otpSent ? (
            <form onSubmit={handleSendOtp}>
              <div className="mb-4">
                <label className="form-label fw-semibold">Phone Number</label>
                <input
                  type="text"
                  className="form-control"
                  value={phoneNumber}
                  onChange={function (e) {
                    setPhoneNumber(e.target.value);
                  }}
                  placeholder="Enter 10-digit phone number"
                  required
                />
              </div>

              <button
                type="submit"
                className="btn btn-success w-100"
                disabled={loading}
              >
                {loading ? "Sending..." : "Send OTP"}
              </button>
            </form>
          ) : (
            <form onSubmit={handleVerifyOtp}>
              <div className="mb-4">
                <label className="form-label fw-semibold">6-digit OTP</label>
                <input
                  type="text"
                  className="form-control"
                  value={otp}
                  onChange={function (e) {
                    setOtp(e.target.value);
                  }}
                  placeholder="Enter OTP"
                  required
                />
              </div>

              <button
                type="submit"
                className="btn btn-success w-100"
                disabled={loading}
              >
                {loading ? "Verifying..." : "Verify OTP"}
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

export default AdminLogin;
